def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        decay_factor = np.exp(-bin_cap / (item + 1))
        if ratio > 4:
            for x in range(4, 0, -1):
                penalty = ((ratio - x) ** 4) / (x ** 2)
                priority += penalty * decay_factor
            priority += np.exp(ratio - 4) * (1 + np.sin(ratio))
        elif 2 < ratio <= 4:
            for m in range(1, int(np.floor(ratio)) + 2):
                priority += (ratio - m)**2 * np.cos(ratio * m) / (m + 1)
            priority += np.log1p(ratio) ** 3
        elif 1 <= ratio <= 2:
            s = 0
            for p in range(1, 6):
                s += ((ratio - 1) ** p) / (p * 2)
            priority = s * np.tanh(3 * (2 - ratio)) + np.sqrt(bin_cap / (item + 1))
        elif 0.5 <= ratio < 1:
            s1 = 0
            s2 = 0
            for n in range(1, 4):
                s1 += ((1 - ratio) ** n) / n
            for k in range(3, 6):
                s2 += ((ratio - 0.5) ** k) / (k * 1.5)
            priority = (s1 - s2) * np.exp(-ratio) + np.sin(bin_cap * ratio)
        elif 0.2 <= ratio < 0.5:
            s = 0
            for n in range(1, 7):
                s += ((0.5 - ratio) ** n) / (n * 2)
            if bin_cap % 3 == 0:
                priority = s * 2 + np.log1p(bin_cap) / (item + 1)
            else:
                priority = s * 0.5 + np.exp(-bin_cap / (item + 2))
        else:
            s = 0
            for k in range(1, 8):
                s += ((0.2 - ratio) ** k) / (k * 3)
            priority = s + (item % 3) * np.sin(bin_cap + ratio * 10)
            if item % 2 == 0:
                priority *= (1 + decay_factor)
            else:
                priority /= (1 + decay_factor)
        if bin_cap < item * 0.4:
            for j in range(1, 4):
                priority += np.log1p(item * bin_cap / j) / j
        elif bin_cap > item * 3:
            for l in range(1, 3):
                priority -= np.exp(-ratio * l) * (1 / (l + 1))
        priorities[i] = priority
    return priorities
